#include <iostream>
#include <vector>
#include <string>

class Polynomial {
public:
    std::vector<int> coefficients;

    Polynomial(std::string expr) {
        parse(expr);
    }

    void parse(const std::string& expr) {
        // Basic parsing logic for simplicity
        int coeff = 1;
        int power = 0;
        for (size_t i = 0; i < expr.size(); ++i) {
            if (expr[i] >= '0' && expr[i] <= '9') {
                coeff *= (expr[i] - '0');
            } else if (expr[i] == '^') {
                power = 1;
            } else if (expr[i] == 'x') {
                coefficients.push_back(coeff * power);
                coeff = 1;
                power = 0;
            }
        }
        coefficients.push_back(coeff * power); // Final term
    }

    Polynomial derivative() const {
        Polynomial deriv;
        for (size_t i = 1; i < coefficients.size(); ++i) {
            deriv.coefficients.push_back(i * coefficients[i]);
        }
        return deriv;
